5320		struct commit *next;
5321		struct commit *merged_merge_bases;
5322		const char *ancestor_name;
5323		struct strbuf merge_base_abbrev = STRBUF_INIT;
5324	
5325		if (!merge_bases) {
5326			if (repo_get_merge_bases(opt->repo, h1, h2,
5327						 &merge_bases) < 0) {
5328				result->clean = -1;
5329				goto out;
5330			}
5331			/* See merge-ort.h:merge_incore_recursive() declaration NOTE */
5332			merge_bases = commit_list_reverse(merge_bases);
5333		}
5334	
5335		merged_merge_bases = pop_commit(&merge_bases);
5336		if (!merged_merge_bases) {
5337			/* if there is no common ancestor, use an empty tree */
5338			struct tree *tree;
5339	
5340			tree = lookup_tree(opt->repo, opt->repo->hash_algo->empty_tree);
5341			merged_merge_bases = make_virtual_commit(opt->repo, tree,
5342								 "ancestor");
5343			ancestor_name = "empty tree";
5344		} else if (merge_bases) {
5345			ancestor_name = "merged common ancestors";
5346		} else if (opt->ancestor) {
5347			ancestor_name = opt->ancestor;
5348		} else {
5349			strbuf_add_unique_abbrev(&merge_base_abbrev,
5350						 &merged_merge_bases->object.oid,
5351						 DEFAULT_ABBREV);
5352			ancestor_name = merge_base_abbrev.buf;
5353		}
5354	
5355		for (next = pop_commit(&merge_bases); next;
5356		     next = pop_commit(&merge_bases)) {
5357			const char *saved_b1, *saved_b2;
5358			struct commit *prev = merged_merge_bases;
5359	
5360			opt->priv->call_depth++;
5361			/*
5362			 * When the merge fails, the result contains files
5363			 * with conflict markers. The cleanness flag is
5364			 * ignored (unless indicating an error), it was never
5365			 * actually used, as result of merge_trees has always
5366			 * overwritten it: the committed "conflicts" were
5367			 * already resolved.
5368			 */
5369			saved_b1 = opt->branch1;
5370			saved_b2 = opt->branch2;
5371			opt->branch1 = "Temporary merge branch 1";
5372			opt->branch2 = "Temporary merge branch 2";
5373			merge_ort_internal(opt, NULL, prev, next, result);
5374			if (result->clean < 0)
5375				goto out;
5376			opt->branch1 = saved_b1;
5377			opt->branch2 = saved_b2;
5378			opt->priv->call_depth--;
5379	
5380			merged_merge_bases = make_virtual_commit(opt->repo,
5381								 result->tree,
5382								 "merged tree");
5383			commit_list_insert(prev, &merged_merge_bases->parents);
5384			commit_list_insert(next, &merged_merge_bases->parents->next);
5385	
5386			clear_or_reinit_internal_opts(opt->priv, 1);
5387		}
5388	
5389		opt->ancestor = ancestor_name;
5390		merge_ort_nonrecursive_internal(opt,
5391						repo_get_commit_tree(opt->repo,
5392								     merged_merge_bases),
5393						repo_get_commit_tree(opt->repo, h1),
5394						repo_get_commit_tree(opt->repo, h2),
5395						result);
5396		strbuf_release(&merge_base_abbrev);
5397		opt->ancestor = NULL;  /* avoid accidental re-use of opt->ancestor */
5398	
5399	out:
